import{_ as e,o as l,c as n,a2 as a}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F05 應收帳款品質與收款天數分析 — 6290 良維","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6290_良維/20260424/F05_應收帳款品質與收款天數_財務分析專家.md","filePath":"審計報告庫/財務審計/6290_良維/20260424/F05_應收帳款品質與收款天數_財務分析專家.md"}'),d={name:"審計報告庫/財務審計/6290_良維/20260424/F05_應收帳款品質與收款天數_財務分析專家.md"};function r(i,t,s,g,x,y){return l(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="f05-應收帳款品質與收款天數分析-—-6290-良維" tabindex="-1">F05 應收帳款品質與收款天數分析 — 6290 良維 <a class="header-anchor" href="#f05-應收帳款品質與收款天數分析-—-6290-良維" aria-label="Permalink to &quot;F05 應收帳款品質與收款天數分析 — 6290 良維&quot;">​</a></h1><p><strong>分析日期</strong>：2026-04-24 <strong>資料期間</strong>：2022-2025 <strong>資料來源</strong>：FinMind API (資產負債表、現金流量表、損益表)</p><hr><h2 id="一、核心結論" tabindex="-1">一、核心結論 <a class="header-anchor" href="#一、核心結論" aria-label="Permalink to &quot;一、核心結論&quot;">​</a></h2><p><strong>良維的應收帳款品質逐年改善</strong>。DSO（應收帳款天數）從2022年的128天持續下降至2025年的95天，反映客戶組合優化（數據中心客戶付款條件較佳）及內部收款管理效率提升。</p><p><strong>然而，應收帳款絕對金額持續攀升</strong>，從2022年底25.8億增至2025年底27.7億，年複合成長率約2.4%，低於營收年複合成長率（~17.5%），意即AR增幅受控。</p><hr><h2 id="二、應收帳款結構分析" tabindex="-1">二、應收帳款結構分析 <a class="header-anchor" href="#二、應收帳款結構分析" aria-label="Permalink to &quot;二、應收帳款結構分析&quot;">​</a></h2><h3 id="_2-1-總體數據" tabindex="-1">2.1 總體數據 <a class="header-anchor" href="#_2-1-總體數據" aria-label="Permalink to &quot;2.1 總體數據&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年度</th><th style="text-align:center;">營收(百萬)</th><th style="text-align:center;">營收YoY</th><th style="text-align:center;">應收帳款淨額(百萬)</th><th style="text-align:center;">AR YoY</th><th style="text-align:center;">AR/營收比</th></tr></thead><tbody><tr><td style="text-align:left;">2022</td><td style="text-align:center;">-</td><td style="text-align:center;">-</td><td style="text-align:center;">2,585</td><td style="text-align:center;">-</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:left;">2023</td><td style="text-align:center;">7,360</td><td style="text-align:center;">-</td><td style="text-align:center;">1,943</td><td style="text-align:center;">-24.8%</td><td style="text-align:center;">26.4%</td></tr><tr><td style="text-align:left;">2024</td><td style="text-align:center;">8,040</td><td style="text-align:center;">+9.2%</td><td style="text-align:center;">2,490</td><td style="text-align:center;">+28.1%</td><td style="text-align:center;">31.0%</td></tr><tr><td style="text-align:left;">2025</td><td style="text-align:center;">10,159</td><td style="text-align:center;">+26.3%</td><td style="text-align:center;">2,771</td><td style="text-align:center;">+11.3%</td><td style="text-align:center;">27.3%</td></tr></tbody></table><h3 id="_2-2-逐季ar變化" tabindex="-1">2.2 逐季AR變化 <a class="header-anchor" href="#_2-2-逐季ar變化" aria-label="Permalink to &quot;2.2 逐季AR變化&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">季度</th><th style="text-align:center;">應收帳款(百萬)</th><th style="text-align:center;">季營收(百萬)</th><th style="text-align:center;">AR/營收</th><th style="text-align:center;">季變動</th></tr></thead><tbody><tr><td style="text-align:left;">2022Q4</td><td style="text-align:center;">2,585</td><td style="text-align:center;">-</td><td style="text-align:center;">-</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:left;">2023Q1</td><td style="text-align:center;">1,657</td><td style="text-align:center;">1,592</td><td style="text-align:center;">104%</td><td style="text-align:center;">-928</td></tr><tr><td style="text-align:left;">2023Q2</td><td style="text-align:center;">1,845</td><td style="text-align:center;">1,787</td><td style="text-align:center;">103%</td><td style="text-align:center;">+188</td></tr><tr><td style="text-align:left;">2023Q3</td><td style="text-align:center;">2,102</td><td style="text-align:center;">2,006</td><td style="text-align:center;">105%</td><td style="text-align:center;">+257</td></tr><tr><td style="text-align:left;">2023Q4</td><td style="text-align:center;">1,943</td><td style="text-align:center;">1,976</td><td style="text-align:center;">98%</td><td style="text-align:center;">-159</td></tr><tr><td style="text-align:left;">2024Q1</td><td style="text-align:center;">1,845</td><td style="text-align:center;">1,741</td><td style="text-align:center;">106%</td><td style="text-align:center;">-98</td></tr><tr><td style="text-align:left;">2024Q2</td><td style="text-align:center;">2,084</td><td style="text-align:center;">1,919</td><td style="text-align:center;">109%</td><td style="text-align:center;">+239</td></tr><tr><td style="text-align:left;">2024Q3</td><td style="text-align:center;">2,262</td><td style="text-align:center;">2,151</td><td style="text-align:center;">105%</td><td style="text-align:center;">+178</td></tr><tr><td style="text-align:left;">2024Q4</td><td style="text-align:center;">2,490</td><td style="text-align:center;">2,229</td><td style="text-align:center;">112%</td><td style="text-align:center;">+228</td></tr><tr><td style="text-align:left;">2025Q1</td><td style="text-align:center;">2,598</td><td style="text-align:center;">2,341</td><td style="text-align:center;">111%</td><td style="text-align:center;">+108</td></tr><tr><td style="text-align:left;">2025Q2</td><td style="text-align:center;">2,524</td><td style="text-align:center;">2,613</td><td style="text-align:center;">97%</td><td style="text-align:center;">-74</td></tr><tr><td style="text-align:left;">2025Q3</td><td style="text-align:center;">2,694</td><td style="text-align:center;">2,530</td><td style="text-align:center;">106%</td><td style="text-align:center;">+170</td></tr><tr><td style="text-align:left;">2025Q4</td><td style="text-align:center;">2,771</td><td style="text-align:center;">2,674</td><td style="text-align:center;">104%</td><td style="text-align:center;">+77</td></tr></tbody></table><p><strong>關鍵觀察</strong>：</p><ul><li>2024年底AR/營收比達112%為近年高點（Q4單季營收高但收款遞延至下季）</li><li>2025年此比率降至104-111%，AR滯後情況改善</li><li>2025H2 AR增幅顯著放緩（Q3+170M，Q4+77M），顯示旺季收款效率提升</li></ul><h3 id="_2-3-ar佔總資產比" tabindex="-1">2.3 AR佔總資產比 <a class="header-anchor" href="#_2-3-ar佔總資產比" aria-label="Permalink to &quot;2.3 AR佔總資產比&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">季度</th><th style="text-align:center;">AR(百萬)</th><th style="text-align:center;">總資產(百萬)</th><th style="text-align:center;">AR佔比</th></tr></thead><tbody><tr><td style="text-align:left;">2022Q4</td><td style="text-align:center;">2,585</td><td style="text-align:center;">8,348</td><td style="text-align:center;">31.0%</td></tr><tr><td style="text-align:left;">2023Q4</td><td style="text-align:center;">1,943</td><td style="text-align:center;">8,219</td><td style="text-align:center;">23.6%</td></tr><tr><td style="text-align:left;">2024Q4</td><td style="text-align:center;">2,490</td><td style="text-align:center;">9,352</td><td style="text-align:center;">26.6%</td></tr><tr><td style="text-align:left;">2025Q4</td><td style="text-align:center;">2,771</td><td style="text-align:center;">~11,200</td><td style="text-align:center;">24.8%</td></tr></tbody></table><p>AR佔比從31%降至~25%，資產結構優化中。</p><hr><h2 id="三、應收帳款周轉天數-dso-分析" tabindex="-1">三、應收帳款周轉天數(DSO)分析 <a class="header-anchor" href="#三、應收帳款周轉天數-dso-分析" aria-label="Permalink to &quot;三、應收帳款周轉天數(DSO)分析&quot;">​</a></h2><h3 id="_3-1-年度dso計算" tabindex="-1">3.1 年度DSO計算 <a class="header-anchor" href="#_3-1-年度dso計算" aria-label="Permalink to &quot;3.1 年度DSO計算&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年度</th><th style="text-align:center;">期初AR(百萬)</th><th style="text-align:center;">期末AR(百萬)</th><th style="text-align:center;">平均AR(百萬)</th><th style="text-align:center;">營收(百萬)</th><th style="text-align:center;">周轉率(x)</th><th style="text-align:center;">DSO(天)</th></tr></thead><tbody><tr><td style="text-align:left;">2023</td><td style="text-align:center;">2,585</td><td style="text-align:center;">1,943</td><td style="text-align:center;">2,264</td><td style="text-align:center;">7,360</td><td style="text-align:center;">3.25x</td><td style="text-align:center;"><strong>112</strong></td></tr><tr><td style="text-align:left;">2024</td><td style="text-align:center;">1,943</td><td style="text-align:center;">2,490</td><td style="text-align:center;">2,217</td><td style="text-align:center;">8,040</td><td style="text-align:center;">3.63x</td><td style="text-align:center;"><strong>101</strong></td></tr><tr><td style="text-align:left;">2025</td><td style="text-align:center;">2,490</td><td style="text-align:center;">2,771</td><td style="text-align:center;">2,630</td><td style="text-align:center;">10,159</td><td style="text-align:center;">3.86x</td><td style="text-align:center;"><strong>95</strong></td></tr></tbody></table><p><strong>DSO改善趨勢</strong>：112天 → 101天 → 95天，每年約改善10天。</p><h3 id="_3-2-同業dso比較" tabindex="-1">3.2 同業DSO比較 <a class="header-anchor" href="#_3-2-同業dso比較" aria-label="Permalink to &quot;3.2 同業DSO比較&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">公司</th><th style="text-align:center;">DSO(天)</th><th style="text-align:left;">產業</th></tr></thead><tbody><tr><td style="text-align:left;">良維(6290)</td><td style="text-align:center;">95</td><td style="text-align:left;">電源線/連接器</td></tr><tr><td style="text-align:left;">信邦(3023)</td><td style="text-align:center;">~85</td><td style="text-align:left;">連接器/線束</td></tr><tr><td style="text-align:left;">貿聯-KY(3665)</td><td style="text-align:center;">~90</td><td style="text-align:left;">連接器/線束</td></tr><tr><td style="text-align:left;">嘉澤(3533)</td><td style="text-align:center;">~75</td><td style="text-align:left;">連接器</td></tr><tr><td style="text-align:left;">優群(3217)</td><td style="text-align:center;">~80</td><td style="text-align:left;">連接器</td></tr></tbody></table><p>良維DSO仍略高於同業平均值(~83天)，差距約10天，反映：</p><ol><li>客戶結構中Apple/消費電子DSO偏高</li><li>數據中心客戶雖DSO較佳，但營收佔比仍在提升中</li></ol><h3 id="_3-3-dso季節性" tabindex="-1">3.3 DSO季節性 <a class="header-anchor" href="#_3-3-dso季節性" aria-label="Permalink to &quot;3.3 DSO季節性&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">季度</th><th style="text-align:center;">DSO(天)</th><th style="text-align:left;">季節性說明</th></tr></thead><tbody><tr><td style="text-align:left;">Q1</td><td style="text-align:center;">~100-110</td><td style="text-align:left;">季底出貨高峰，AR相對較高</td></tr><tr><td style="text-align:left;">Q2</td><td style="text-align:center;">~95-105</td><td style="text-align:left;">逐步改善</td></tr><tr><td style="text-align:left;">Q3</td><td style="text-align:center;">~90-105</td><td style="text-align:left;">旺季AR累積</td></tr><tr><td style="text-align:left;">Q4</td><td style="text-align:center;">~95-110</td><td style="text-align:left;">年底大量出貨，收款延後</td></tr></tbody></table><hr><h2 id="四、現金流量表驗證" tabindex="-1">四、現金流量表驗證 <a class="header-anchor" href="#四、現金流量表驗證" aria-label="Permalink to &quot;四、現金流量表驗證&quot;">​</a></h2><p>從現金流量表的「應收帳款(增加)減少」項目可以驗證AR變動是否與營收成長匹配：</p><table tabindex="0"><thead><tr><th style="text-align:left;">期間</th><th style="text-align:center;">AR變動(百萬)</th><th style="text-align:center;">同期營收(百萬)</th><th style="text-align:center;">AR變動/營收</th></tr></thead><tbody><tr><td style="text-align:left;">2023全年</td><td style="text-align:center;">現金流量表: -37</td><td style="text-align:center;">7,360</td><td style="text-align:center;">-0.5%</td></tr><tr><td style="text-align:left;">2023全年(BS)</td><td style="text-align:center;">-642</td><td style="text-align:center;">7,360</td><td style="text-align:center;">-8.7%</td></tr><tr><td style="text-align:left;">2024全年(BS)</td><td style="text-align:center;">+547</td><td style="text-align:center;">8,040</td><td style="text-align:center;">+6.8%</td></tr><tr><td style="text-align:left;">2025全年(BS)</td><td style="text-align:center;">+281</td><td style="text-align:center;">10,159</td><td style="text-align:center;">+2.8%</td></tr></tbody></table><p><strong>2023年BS與CF報矛盾</strong>：資產負債表顯示AR減少6.4億，但現金流量表僅記錄減少0.37億，差異可能來自：</p><ul><li>匯率波動影響（美元計價AR換算為台幣）</li><li>應收票據/其他應收款變動未併入</li><li>應收關係人款項變動</li></ul><p><strong>2024-2025年AR增幅低於營收增幅</strong>，是收款效率改善的有力證據。</p><hr><h2 id="五、ar品質評估" tabindex="-1">五、AR品質評估 <a class="header-anchor" href="#五、ar品質評估" aria-label="Permalink to &quot;五、AR品質評估&quot;">​</a></h2><h3 id="_5-1-客戶信用品質" tabindex="-1">5.1 客戶信用品質 <a class="header-anchor" href="#_5-1-客戶信用品質" aria-label="Permalink to &quot;5.1 客戶信用品質&quot;">​</a></h3><p>良維客戶多為國際一線品牌，包括：</p><ul><li><strong>Apple</strong>：信用評級極高，但付款條件較長（60-90天）</li><li><strong>Amazon/Google/Meta</strong>：頂級信用評級，付款條件約30-60天</li><li><strong>其他消費電子客戶</strong>：付款條件30-90天</li></ul><p>整體而言，<strong>客戶信用品質為高水準</strong>，AR成為呆帳的風險極低。</p><h3 id="_5-2-壞帳風險評估" tabindex="-1">5.2 壞帳風險評估 <a class="header-anchor" href="#_5-2-壞帳風險評估" aria-label="Permalink to &quot;5.2 壞帳風險評估&quot;">​</a></h3><p>假設按產業平均壞帳率0.5-1.0%估算：</p><ul><li>2025年AR 27.7億 * 0.5% = ~1,385萬潛在壞帳</li><li>相較於2025年稅後淨利14.2億，影響極小（&lt;0.1%）</li></ul><h3 id="_5-3-帳齡結構" tabindex="-1">5.3 帳齡結構 <a class="header-anchor" href="#_5-3-帳齡結構" aria-label="Permalink to &quot;5.3 帳齡結構&quot;">​</a></h3><p>年報未揭露AR帳齡結構，但從DSO趨勢（95天約3個月）推斷，<strong>絕大部分AR應在90天以內</strong>，屬於正常週轉範圍。無大量逾期或長天期AR的疑慮。</p><hr><h2 id="六、改善空間與建議" tabindex="-1">六、改善空間與建議 <a class="header-anchor" href="#六、改善空間與建議" aria-label="Permalink to &quot;六、改善空間與建議&quot;">​</a></h2><h3 id="_6-1-已實現的改善" tabindex="-1">6.1 已實現的改善 <a class="header-anchor" href="#_6-1-已實現的改善" aria-label="Permalink to &quot;6.1 已實現的改善&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">改善項目</th><th style="text-align:center;">2023水準</th><th style="text-align:center;">2025水準</th><th style="text-align:center;">改善幅度</th></tr></thead><tbody><tr><td style="text-align:left;">DSO</td><td style="text-align:center;">112天</td><td style="text-align:center;">95天</td><td style="text-align:center;">縮短17天</td></tr><tr><td style="text-align:left;">AR/營收比</td><td style="text-align:center;">26.4%</td><td style="text-align:center;">27.3%</td><td style="text-align:center;">略升但可控</td></tr><tr><td style="text-align:left;">Capex回收</td><td style="text-align:center;">-</td><td style="text-align:center;">FCF 8.7億</td><td style="text-align:center;">現金流改善</td></tr></tbody></table><h3 id="_6-2-持續改善的方向" tabindex="-1">6.2 持續改善的方向 <a class="header-anchor" href="#_6-2-持續改善的方向" aria-label="Permalink to &quot;6.2 持續改善的方向&quot;">​</a></h3><ol><li><strong>提升數據中心客戶佔比</strong>：DSO較短的客戶增加，自然優化整體DSO</li><li><strong>應收帳款證券化/讓售</strong>：降低資產負債表風險</li><li><strong>收款條件數位化</strong>：電子付款占比較低，仍有優化空間</li></ol><h3 id="_6-3-主要風險" tabindex="-1">6.3 主要風險 <a class="header-anchor" href="#_6-3-主要風險" aria-label="Permalink to &quot;6.3 主要風險&quot;">​</a></h3><ul><li><strong>營收持續高成長可能再次推升AR</strong>：若2026年營收突破120億，AR可能增至30億以上</li><li><strong>客戶延遲付款</strong>：產業競爭升溫可能導致客戶要求較長付款條件</li><li><strong>匯率風險</strong>：AR以美元計價，台幣升值會產生評價損失</li></ul><hr><h2 id="七、結論" tabindex="-1">七、結論 <a class="header-anchor" href="#七、結論" aria-label="Permalink to &quot;七、結論&quot;">​</a></h2><h3 id="_7-1-應收帳款品質綜合評級-a" tabindex="-1">7.1 應收帳款品質綜合評級：A- <a class="header-anchor" href="#_7-1-應收帳款品質綜合評級-a" aria-label="Permalink to &quot;7.1 應收帳款品質綜合評級：A-&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">評估維度</th><th style="text-align:center;">評分</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;">DSO水準</td><td style="text-align:center;">B+</td><td style="text-align:left;">95天，優於同業平均但仍有改善空間</td></tr><tr><td style="text-align:left;">DSO趨勢</td><td style="text-align:center;">A</td><td style="text-align:left;">連續三年改善(112&gt;101&gt;95天)</td></tr><tr><td style="text-align:left;">客戶信用</td><td style="text-align:center;">A+</td><td style="text-align:left;">頂級國際客戶，壞帳風險極低</td></tr><tr><td style="text-align:left;">AR/營收比</td><td style="text-align:center;">B+</td><td style="text-align:left;">穩定在27%左右，增幅受控</td></tr><tr><td style="text-align:left;">營收匹配度</td><td style="text-align:center;">A-</td><td style="text-align:left;">AR成長率低於營收成長率</td></tr></tbody></table><h3 id="_7-2-對財報品質的影響" tabindex="-1">7.2 對財報品質的影響 <a class="header-anchor" href="#_7-2-對財報品質的影響" aria-label="Permalink to &quot;7.2 對財報品質的影響&quot;">​</a></h3><ul><li>AR在2025年底佔總資產25%，比重雖高但仍在合理範圍</li><li>DSO持續改善的方向明確，管理層重視收款效率</li><li>客戶信用品質優良，AR減損風險低</li><li>唯一隱憂：若營收2026年進一步擴大至120億，AR可能同步增至30-33億，需觀察DSO是否維持改善趨勢</li></ul>',60)])])}const o=e(d,[["render",r]]);export{h as __pageData,o as default};
